parameters.jsCode:
const item = $input.first();
  const aiResponse = item.json;

  let analysis = null;
  let parseError = null;

  // Extract JSON from AI response
  try {
    let responseText = '';

    if (aiResponse.text) {
      responseText = aiResponse.text;
    } else if (aiResponse.message?.content) {
      responseText = aiResponse.message.content;
    } else if (aiResponse.output && Array.isArray(aiResponse.output)) {
      responseText = aiResponse.output[0]?.content?.[0]?.text || '';
    } else if (typeof aiResponse === 'string') {
      responseText = aiResponse;
    }

    const jsonMatch = responseText.match(/\{[\s\S]*\}/);
    if (jsonMatch) analysis = JSON.parse(jsonMatch[0]);
  } catch (e) {
    parseError = e.message;
  }

  const originalData = $('Combine Context').first().json;
  const scannerData = originalData.originalGrantData || {};

  if (!analysis) {
    return [{
      json: {
        success: false,
        error: 'Failed to parse AI response',
        parseError,
        sourceUrl: originalData.sourceUrl,
        sourceType: originalData.sourceType
      }
    }];
  }

  // ===== BUILD RESULT =====
  const score = (analysis.overallScore || 'YELLOW').toLowerCase();
  const allowedScores = ['green', 'yellow', 'red'];
  const screening_result = allowedScores.includes(score) ? score : 'yellow';

  // Calculate confidence from dimension scores if available
  const dims = analysis.dimensionScores || {};
  const hasAllDimensions = dims.missionAlignment != null
    && dims.targetPopulation != null
    && dims.serviceFit != null
    && dims.geographicAlignment != null
    && dims.organizationalCapacity != null;

  const calculatedConfidence = hasAllDimensions
    ? dims.missionAlignment + dims.targetPopulation + dims.serviceFit + dims.geographicAlignment + dims.organizationalCapacity
    : (analysis.confidence || 50);

  const result = {
    success: true,
    data: {
      id: analysis.grantid,
      org_id: analysis.org_id || originalData.org_id || scannerData.org_id,
      title: analysis.grantTitle,
      stage: "pending_approval",
      funder_name: analysis.agency || scannerData.agency || 'Unknown',
      amount: analysis.fundingRange || scannerData.awardRange || null,
      deadline: analysis.deadline || scannerData.deadline,

      eligibility: {
        score: score.toUpperCase(),
        confidence: calculatedConfidence,
        indicator: {
          green: '🟢',
          yellow: '🟡',
          red: '🔴'
        }[score] || '⚪',
        dimension_scores: {
          mission_alignment: dims.missionAlignment || 0,
          target_population: dims.targetPopulation || 0,
          service_fit: dims.serviceFit || 0,
          geographic_alignment: dims.geographicAlignment || 0,
          organizational_capacity: dims.organizationalCapacity || 0
        }
      },

      screening_score: calculatedConfidence,

      screening_notes: analysis.summary || 'Unable to determine eligibility',
      categories: analysis.categories || {},
      concerns: analysis.concerns || [],
      recommendations: analysis.recommendations || [],

      source: {
        url: originalData.sourceUrl,
        type: originalData.sourceType,
        analyzedAt: new Date().toISOString()
      }
    }
  };
  return result;

return items.map(item => {
